import{_ as n,C as l,o as a,c as r,a3 as o,b as i,w as c,a as p,E as s,a4 as d}from"./chunks/framework.aYYe0dfI.js";const P=JSON.parse('{"title":"Namespace clore::net::anthropic","description":"clore::net::anthropic 命名空间封装了与 Anthropic 语言模型 API 的异步交互，提供了一组非阻塞的调用入口。其核心函数包括 call_llm_async（接受模型标识、提示文本和事件循环等参数）、call_completion_async 用于轮询/等待异步结果，以及 call_structured_async 用于期望结构化响应的请求。所有函数均返回一个整数句柄，调用者可通过该句柄在后续查询或取消操作；它们依赖外部的 kota::event_loop 驱动异步执行，调用者需确保事件循环保持活跃。该命名空间在 clore 网络库中承担针对 Anthropic 服务的专用通信层角色。","frontmatter":{"title":"Namespace clore::net::anthropic","description":"clore::net::anthropic 命名空间封装了与 Anthropic 语言模型 API 的异步交互，提供了一组非阻塞的调用入口。其核心函数包括 call_llm_async（接受模型标识、提示文本和事件循环等参数）、call_completion_async 用于轮询/等待异步结果，以及 call_structured_async 用于期望结构化响应的请求。所有函数均返回一个整数句柄，调用者可通过该句柄在后续查询或取消操作；它们依赖外部的 kota::event_loop 驱动异步执行，调用者需确保事件循环保持活跃。该命名空间在 clore 网络库中承担针对 Anthropic 服务的专用通信层角色。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/namespaces/clore/net/anthropic/index.md","filePath":"zh/clore/namespaces/clore/net/anthropic/index.md"}'),h={name:"zh/clore/namespaces/clore/net/anthropic/index.md"};function m(u,e,_,f,y,k){const t=l("Mermaid");return a(),r("div",null,[e[1]||(e[1]=o('<h1 id="namespace-clore-net-anthropic" tabindex="-1">Namespace <code>clore::net::anthropic</code> <a class="header-anchor" href="#namespace-clore-net-anthropic" aria-label="Permalink to &quot;Namespace `clore::net::anthropic`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>clore::net::anthropic</code> 命名空间封装了与 Anthropic 语言模型 API 的异步交互，提供了一组非阻塞的调用入口。其核心函数包括 <code>call_llm_async</code>（接受模型标识、提示文本和事件循环等参数）、<code>call_completion_async</code> 用于轮询/等待异步结果，以及 <code>call_structured_async</code> 用于期望结构化响应的请求。所有函数均返回一个整数句柄，调用者可通过该句柄在后续查询或取消操作；它们依赖外部的 <code>kota::event_loop</code> 驱动异步执行，调用者需确保事件循环保持活跃。该命名空间在 clore 网络库中承担针对 Anthropic 服务的专用通信层角色。</p><h2 id="diagram" tabindex="-1">Diagram <a class="header-anchor" href="#diagram" aria-label="Permalink to &quot;Diagram&quot;">​</a></h2>',4)),(a(),i(d,null,{default:c(()=>[s(t,{id:"mermaid-12",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20NS%5B%22anthropic%22%5D%0A%20%20%20%20NSC0%5B%22detail%22%5D%0A%20%20%20%20NS%20--%3E%20NSC0%0A%20%20%20%20NSC1%5B%22protocol%22%5D%0A%20%20%20%20NS%20--%3E%20NSC1%0A%20%20%20%20NSC2%5B%22schema%22%5D%0A%20%20%20%20NS%20--%3E%20NSC2%0A"})]),fallback:c(()=>[...e[0]||(e[0]=[p(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h2 id="subnamespaces" tabindex="-1">Subnamespaces <a class="header-anchor" href="#subnamespaces" aria-label="Permalink to &quot;Subnamespaces&quot;">​</a></h2><ul><li><a href="./detail/"><code>clore::net::anthropic::detail</code></a></li><li><a href="./protocol/"><code>clore::net::anthropic::protocol</code></a></li><li><a href="./schema/"><code>clore::net::anthropic::schema</code></a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-anthropic-call-completion-async" tabindex="-1"><code>clore::net::anthropic::call_completion_async</code> <a class="header-anchor" href="#clore-net-anthropic-call-completion-async" aria-label="Permalink to &quot;`clore::net::anthropic::call_completion_async`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:722</code></p><p>Definition: <code>network/anthropic.cppm:764</code></p><p>Implementation: <a href="./../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p>该函数发起一个对 Anthropic 的 completion API 的异步调用，并返回一个整数标识符（可能是请求 ID 或任务句柄）。调用者需提供一个整数参数（应代表预定义的配置或模型选择）和一个 <code>kota::event_loop</code> 引用以驱动异步执行；函数返回的整数可用于后续跟踪或取消操作，具体由事件循环调度。调用者负责确保事件循环保持活动状态直到回调完成。</p><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used as a building block for higher-level Anthropic interaction functions in the <code>clore::net::anthropic</code> namespace</li></ul><h3 id="clore-net-anthropic-call-llm-async" tabindex="-1"><code>clore::net::anthropic::call_llm_async</code> <a class="header-anchor" href="#clore-net-anthropic-call-llm-async" aria-label="Permalink to &quot;`clore::net::anthropic::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:732</code></p><p>Definition: <code>network/anthropic.cppm:782</code></p><p>Implementation: <a href="./../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p>该函数启动一次对 Anthropic LLM 的异步调用。调用者需提供三个字符串视图参数（含义由上下文约定，通常分别对应 API 密钥、模型标识和提示文本）以及一个 <code>kota::event_loop</code> 引用用于调度异步事件。函数返回一个整数，该整数代表此次异步请求的标识符或执行状态，调用者可据此后续查询或取消操作。</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Async LLM completion call from coroutine context</li><li>Wrapper that delegates to protocol-specific implementation</li><li>Used in combination with <code>.or_fail()</code> to convert errors</li></ul><h3 id="clore-net-anthropic-call-llm-async-1" tabindex="-1"><code>clore::net::anthropic::call_llm_async</code> <a class="header-anchor" href="#clore-net-anthropic-call-llm-async-1" aria-label="Permalink to &quot;`clore::net::anthropic::call_llm_async`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:726</code></p><p>Definition: <code>network/anthropic.cppm:771</code></p><p>Implementation: <a href="./../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p>发起对 Anthropic 语言模型的异步调用。函数接受三个 <code>std::string_view</code> 参数（分别表示模型标识、系统提示与用户消息）、一个 <code>int</code> 参数（超时或最大 token 数）以及一个 <code>kota::event_loop</code> 引用用于驱动异步操作。返回一个 <code>int</code> 句柄，调用者可随后使用 <code>call_completion_async</code> 轮询或等待结果。调用者须确保提供的 <code>kota::event_loop</code> 在调用期间保持活动状态。</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to send prompts to Anthropic and await responses asynchronously</li><li>Called from other async functions within the <code>clore::net::anthropic</code> namespace</li></ul><h3 id="clore-net-anthropic-call-structured-async" tabindex="-1"><code>clore::net::anthropic::call_structured_async</code> <a class="header-anchor" href="#clore-net-anthropic-call-structured-async" aria-label="Permalink to &quot;`clore::net::anthropic::call_structured_async`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:739</code></p><p>Definition: <code>network/anthropic.cppm:794</code></p><p>Implementation: <a href="./../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p><code>clore::net::anthropic::call_structured_async</code> 是一个异步函数模板，调用者通过它向 Anthropic 的 LLM 发起请求，并期望获得一个由模板参数 <code>T</code> 描述的结构化响应。调用者需提供三个 <code>std::string_view</code> 参数（通常分别为模型标识、提示内容及其他配置信息）和一个 <code>kota::event_loop</code> 引用，函数返回一个 <code>int</code> 句柄。该句柄可用于后续通过 <code>clore::net::anthropic::call_completion_async</code> 等接口查询异步操作的状态或取得最终结果。调用者必须确保提供的 <code>kota::event_loop</code> 处于活跃运行状态，否则异步调用无法正常完成。</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to make structured asynchronous calls to the Anthropic API</li><li>Called with model identifier, system prompt, user prompt, and an event loop</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore::net</a></li><li><a href="./detail/">Namespace clore::net::anthropic::detail</a></li><li><a href="./protocol/">Namespace clore::net::anthropic::protocol</a></li><li><a href="./schema/">Namespace clore::net::anthropic::schema</a></li></ul>',33))])}const A=n(h,[["render",m]]);export{P as __pageData,A as default};
